// Compliant: Final else clause handles default case
func GetUserStatus(user User) string {
    if user.IsActive {
        return "active"
    } else if user.IsPending {
        return "pending"
    } else if user.IsSuspended {
        return "suspended"
    } else {
        return "inactive" // Default case
    }
}

// Compliant: All cases explicitly handled
func CalculateDiscount(amount float64) float64 {
    if amount > 1000 {
        return amount * 0.1
    } else if amount > 500 {
        return amount * 0.05
    } else if amount > 100 {
        return amount * 0.02
    } else {
        return 0 // No discount for small amounts
    }
}

